var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"하아...... 컨디션 조절도 못하고 병가를 써 버리다니......","JPN":"はあ……体調管理ができず病欠になるなんて……","ENG":"*Sigh* I can't believe I had to take sick leave because I overworked myself...","TWN":"哈啊……沒能管理好身體，就突然休了病假……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 레나 양은 잘하고 있으려나?","JPN":"今頃レナさんはうまくやってくれているかな？","ENG":"I wonder how Lena's doing?","TWN":"也不知道蕾娜能不能應付得來？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"모르는 일이 있으면 전화 달라고 했는데 문자 한 통 안 왔고......","JPN":"わからないことがあれば電話してと言ったのに、メッセージも何もないし……","ENG":"I told her to call me if she gets stuck, but she hasn't texted at all.","TWN":"跟她說有什麼不懂的就給我打電話的，怎麼連個簡訊都沒有……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"혹시......?","JPN":"もしかして……？","ENG":"Wait... Could she be...","TWN":"難道……？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이미 회사가 입은 손해는 레나 양이 책임질 수 있는 범위를 넘어섰어요.","JPN":"すでに会社に与えた損害は、レナさんが責任を負える限度を超えています。","ENG":"The amount of damage suffered by the company is already well beyond what you can compensate, Lena.","TWN":"公司受到的損失，已經不是蕾娜妳可以負責的程度了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"긴 말 안 하겠습니다. 내일부터는 출근하지 않으셔도 돼요.","JPN":"単刀直入に言います。明日から出社しなくて大丈夫です。","ENG":"I'll be blunt. I'm going to have to let you go now.","TWN":"廢話就不多說了，明天開始妳不用上班了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"잘못했어요, 부사장님! 한 번만 더 기회를 주세요!","JPN":"も、申し訳ございません、副社長！　もう一度チャンスをください！","ENG":"I'm so sorry, ma'am! Please give me one more chance!","TWN":"副總，對不起！再給我一次機會吧！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"설마...... 그런 일이 벌어지진 않았겠지?","JPN":"まさか……そんなことが起きたりはしてないよね……？","ENG":"She's not going to get fired like that... is she?","TWN":"不會……不會發生這種事吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"기다리세요, 레나 양! 지금 갈게요!","JPN":"待っててください、レナさん！　ナカシマが今行きます！","ENG":"Hold on, Lena! I'll be right there!","TWN":"等我，蕾娜！我現在就去！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>업계인들이 만드는 뉴스, 태스크포스 리빌. 다음 소식입니다.</color>","JPN":"<color=#ffd34c>業界人が作るニュース、タスクフォース・リビール。次のニュースです。</color>","ENG":"<color=#ffd34c>This is TASKFORCE Reveal, your trusted news source on all things in the industry. Here's the news.</color>","TWN":"<color=#ffd34c>業界人的新聞，特遣勢力為您報導下一個消息。</color>"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최근 그라운드 원 시가지에서 측정되는 침식파가 불안정한 양상을 띄고 있다고 밝혔습니다.</color>","JPN":"<color=#ffd34c>最近グラウンド・ワン市街地で計測される侵食波が、不安定な状況であることが明らかになりました。</color>","ENG":"<color=#ffd34c>Recently, the Corruption Rays detected from Ground One have shown signs of instability.</color>","TWN":"<color=#ffd34c>最近發現在G1市區測到的侵蝕波情況不穩定。</color>"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국은 관할 태스크포스들이 제출한 13개 구역의 통행 자제를 권고하였으며......</color>","JPN":"<color=#ffd34c>都市管理局は管轄タスクフォースカンパニーが提出した13のエリアに通行を控えることを勧告し……</color>","ENG":"<color=#ffd34c>The City Management has urged restricted movement in the 13 sectors recommended by the respective TASKFORCEs...</color>","TWN":"<color=#ffd34c>城市管理局建議管轄特遣勢力提交的13個區域禁止通行……</color>"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"왠지...... 평소보다 더 차분하네?","JPN":"なんだか……いつもより落ち着いている……？","ENG":"Strange... It's actually a lot more serene than usual.","TWN":"感覺……比平時冷靜呢。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잘 왔네, 관리부장. 푹 쉬었나?","JPN":"おおーおはよう、管理部長。ゆっくり休めたか？","ENG":"Welcome back, Manager. Are you feeling better?","TWN":"妳來得正好，管理部長。休息足夠了嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 네! 덕분에!","JPN":"あ、はい！　おかげさまで。","ENG":"Oh, yes! Thank you.","TWN":"啊，是！謝謝！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};